def generate_id():
    """Generate a unique SAML ID."""
    return "_" + uuid.uuid4().hex


def utc_now():
    """Get current UTC time."""
    return datetime.datetime.now(datetime.timezone.utc)


def format_datetime(dt):
    """Format datetime for SAML."""
    return dt.strftime("%Y-%m-%dT%H:%M:%SZ")


def hash_password(password, salt=None):
    """Hash password using PBKDF2 with SHA-256."""
    if salt is None:
        salt = os.urandom(32)
    key = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, 100000)
    return salt + key


def verify_password(password, stored_hash):
    """Verify password against stored hash."""
    salt = stored_hash[:32]
    expected = hash_password(password, salt)
    return hashlib.compare_digest(expected, stored_hash)


def initialize_users():
    """Initialize user password hashes."""
    default_passwords = {
        "admin": "change-me-admin-password",
        "user1": "change-me-user1-password",
    }
    for username, password in default_passwords.items():
        if username in USERS:
            USERS[username]["password_hash"] = hash_password(password)


