class AuthnRequestParser:
    """Parse and validate incoming SAML AuthnRequest."""

    def __init__(self, saml_request_b64):
        self.raw = base64.b64decode(saml_request_b64)
        self.root = None
        self.request_id = None
        self.issuer = None
        self.acs_url = None
        self.destination = None
        self.name_id_format = None

    def parse(self):
        """Parse the AuthnRequest XML securely."""
        parser = etree.XMLParser(
            resolve_entities=False,
            no_network=True,
            dtd_validation=False,
            load_dtd=False,
            huge_tree=False,
        )
        try:
            self.root = etree.fromstring(self.raw, parser=parser)
        except etree.XMLSyntaxError as e:
            raise ValueError(f"Invalid XML in AuthnRequest: {e}")

        # Validate root element
        tag = etree.QName(self.root.tag)
        if tag.namespace != SAMLP_NS or tag.localname != "AuthnRequest":
            raise ValueError("Root element is not a SAML AuthnRequest")

        self.request_id = self.root.get("ID")
        if not self.request_id:
            raise ValueError("AuthnRequest missing ID attribute")

        self.destination = self.root.get("Destination")
        self.acs_url = self.root.get("AssertionConsumerServiceURL")

        # Extract Issuer
        issuer_elem = self.root.find(f"{{{SAML_NS}}}Issuer")
        if issuer_elem is not None and issuer_elem.text:
            self.issuer = issuer_elem.text.strip()

        # Extract NameIDPolicy
        name_id_policy = self.root.find(f"{{{SAMLP_NS}}}NameIDPolicy")
        if name_id_policy is not None:
            self.name_id_format = name_id_policy.get("Format")

        return self

    def validate(self):
        """Validate the parsed AuthnRequest."""
        if not self.issuer:
            raise ValueError("AuthnRequest missing Issuer")

        if self.issuer not in REGISTERED_SPS:
            raise ValueError(f"Unknown Service Provider: {self.issuer}")

        sp_config = REGISTERED_SPS[self.issuer]

        # Validate ACS URL matches registered SP
        if self.acs_url and self.acs_url != sp_config["acs_url"]:
            raise ValueError(
                f"ACS URL mismatch: got {self.acs_url}, expected {sp_config['acs_url']}"
            )

        # Use registered ACS URL if not provided
        if not self.acs_url:
            self.acs_url = sp_config["acs_url"]

        # Validate Destination
        if self.destination and self.destination != IDP_CONFIG["sso_url"]:
            raise ValueError(f"Invalid Destination: {self.destination}")

        return self


