class SAMLResponseBuilder:
    """Build and sign SAML responses."""

    def __init__(self, cert_pem, key_pem):
        self.cert_pem = cert_pem
        self.key_pem = key_pem

    def build_response(
        self,
        in_response_to,
        sp_entity_id,
        acs_url,
        username,
        user_attrs,
        name_id_format=None,
    ):
        """Build a complete SAML Response with signed Assertion."""
        now = utc_now()
        not_before = now - datetime.timedelta(
            seconds=IDP_CONFIG["allowed_clock_skew_seconds"]
        )
        not_on_or_after = now + datetime.timedelta(
            seconds=IDP_CONFIG["response_validity_seconds"]
        )
        session_not_on_or_after = now + datetime.timedelta(hours=8)

        response_id = generate_id()
        assertion_id = generate_id()

        if not name_id_format:
            name_id_format = (
                "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            )

        name_id_value = user_attrs.get("email", username)

        # Build Response element
        response = etree.Element(
            f"{{{SAMLP_NS}}}Response",
            nsmap={"samlp": SAMLP_NS, "saml": SAML_NS},
        )
        response.set("ID", response_id)
        response.set("Version", "2.0")
        response.set("IssueInstant", format_datetime(now))
        response.set("Destination", acs_url)
        response.set("InResponseTo", in_response_to)

        # Response Issuer
        resp_issuer = etree.SubElement(response, f"{{{SAML_NS}}}Issuer")
        resp_issuer.text = IDP_CONFIG["entity_id"]

        # Status
        status = etree.SubElement(response, f"{{{SAMLP_NS}}}Status")
        status_code = etree.SubElement(status, f"{{{SAMLP_NS}}}StatusCode")
        status_code.set(
            "Value", "urn:oasis:names:tc:SAML:2.0:status:Success"
        )

        # Assertion
        assertion = etree.SubElement(response, f"{{{SAML_NS}}}Assertion")
        assertion.set("xmlns:saml", SAML_NS)
        assertion.set("ID", assertion_id)
        assertion.set("Version", "2.0")
        assertion.set("IssueInstant", format_datetime(now))

        # Assertion Issuer
        assert_issuer = etree.SubElement(assertion, f"{{{SAML_NS}}}Issuer")
        assert_issuer.text = IDP_CONFIG["entity_id"]

        # Subject
        subject = etree.SubElement(assertion, f"{{{SAML_NS}}}Subject")
        name_id = etree.SubElement(subject, f"{{{SAML_NS}}}NameID")
        name_id.set("Format", name_id_format)
        name_id.set("SPNameQualifier", sp_entity_id)
        name_id.text = name_id_value

        subject_confirmation = etree.SubElement(
            subject, f"{{{SAML_NS}}}SubjectConfirmation"
        )
        subject_confirmation.set(
            "Method", "urn:oasis:names:tc:SAML:2.0:cm:bearer"
        )
        subject_confirmation_data = etree.SubElement(
            subject_confirmation, f"{{{SAML_NS}}}SubjectConfirmationData"
        )
        subject_confirmation_data.set("InResponseTo", in_response_to)
        subject_confirmation_data.set(
            "NotOnOrAfter", format_datetime(not_on_or_after)
        )
        subject_confirmation_data.set("Recipient", acs_url)

        # Conditions
        conditions = etree.SubElement(assertion, f"{{{SAML_NS}}}Conditions")
        conditions.set("NotBefore", format_datetime(not_before))
        conditions.set("NotOnOrAfter", format_datetime(not_on_or_after))

        audience_restriction = etree.SubElement(
            conditions, f"{{{SAML_NS}}}AudienceRestriction"
        )
        audience = etree.SubElement(
            audience_restriction, f"{{{SAML_NS}}}Audience"
        )
        audience.text = sp_entity_id

        # AuthnStatement
        authn_statement = etree.SubElement(
            assertion, f"{{{SAML_NS}}}AuthnStatement"
        )
        authn_statement.set("AuthnInstant", format_datetime(now))
        authn_statement.set(
            "SessionNotOnOrAfter", format_datetime(session_not_on_or_after)
        )
        authn_statement.set("SessionIndex", generate_id())

        authn_context = etree.SubElement(
            authn_statement, f"{{{SAML_NS}}}AuthnContext"
        )
        authn_context_class_ref = etree.SubElement(
            authn_context, f"{{{SAML_NS}}}AuthnContextClassRef"
        )
        authn_context_class_ref.text = (
            "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport"
        )

        # AttributeStatement
        attr_statement = etree.SubElement(
            assertion, f"{{{SAML_NS}}}AttributeStatement"
        )

        self._add_attribute(
            attr_statement,
            "email",
            "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
            user_attrs.get("email", ""),
        )
        self._add_attribute(
            attr_statement,
            "firstName",
            "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
            user_attrs.get("first_name", ""),
        )
        self._add_attribute(
            attr_statement,
            "lastName",
            "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
            user_attrs.get("last_name", ""),
        )

        for role in user_attrs.get("roles", []):
            self._add_attribute(
                attr_statement,
                "role",
                "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
                role,
            )

        # Sign the Assertion
        self._sign_assertion(assertion)

        return response

    def _add_attribute(self, parent, name, name_format, value):
        """Add a SAML attribute to an AttributeStatement."""
        attr = etree.SubElement(parent, f"{{{SAML_NS}}}Attribute")
        attr.set("Name", name)
        attr.set("NameFormat", name_format)

        attr_value = etree.SubElement(attr, f"{{{SAML_NS}}}AttributeValue")
        attr_value.set(
            f"{{{NSMAP['xsi']}}}type",
            "xs:string",
        )
        attr_value.text = value

    def _sign_assertion(self, assertion):
        """Sign the SAML Assertion using XML Digital Signature."""
        # Create Signature template - insert after Issuer element
        issuer_elem = assertion.find(f"{{{SAML_NS}}}Issuer")
        issuer_index = list(assertion).index(issuer_elem)

        # Build the Signature element
        signature_node = xmlsec.template.create(
            assertion,
            c14n_method=xmlsec.constants.TransformExclC14N,
            sign_method=xmlsec.constants.TransformRsaSha256,
            ns="ds",
        )

        # Insert Signature after Issuer
        assertion.insert(issuer_index + 1, signature_node)

        # Add Reference to the Assertion
        assertion_id = assertion.get("ID")
        ref = xmlsec.template.add_reference(
            signature_node,
            xmlsec.constants.TransformSha256,
            uri=f"#{assertion_id}",
        )

        # Add transforms
        xmlsec.template.add_transform(ref, xmlsec.constants.TransformEnveloped)
        xmlsec.template.add_transform(ref, xmlsec.constants.TransformExclC14N)

        # Add KeyInfo
        key_info = xmlsec.template.ensure_key_info(signature_node)
        x509_data = xmlsec.template.add_x509_data(key_info)
        xmlsec.template.x509_data_add_certificate(x509_data)

        # Sign
        ctx = xmlsec.SignatureContext()
        ctx.key = xmlsec.Key.from_memory(
            self.key_pem, xmlsec.constants.KeyDataFormatPem
        )
        ctx.key.load_cert(self.cert_pem, xmlsec.constants.KeyDataFormatPem)
        ctx.sign(signature_node)

    def serialize_response(self, response):
        """Serialize the SAML Response to base64-encoded string."""
        xml_bytes = etree.tostring(
            response, xml_declaration=True, encoding="UTF-8"
        )
        return base64.b64encode(xml_bytes).decode("utf-8")


