class SessionManager:
    """Simple in-memory session manager with CSRF protection."""

    def __init__(self):
        self.sessions = {}
        self.pending_requests = {}

    def create_session(self, username):
        """Create a new session for an authenticated user."""
        session_id = os.urandom(32).hex()
        self.sessions[session_id] = {
            "username": username,
            "created": utc_now(),
            "last_active": utc_now(),
        }
        return session_id

    def get_session(self, session_id):
        """Get session data, validating expiry."""
        if not session_id or session_id not in self.sessions:
            return None

        session = self.sessions[session_id]
        # Session expires after 8 hours
        if (utc_now() - session["created"]).total_seconds() > 28800:
            del self.sessions[session_id]
            return None

        session["last_active"] = utc_now()
        return session

    def destroy_session(self, session_id):
        """Destroy a session."""
        self.sessions.pop(session_id, None)

    def store_pending_request(self, authn_request_data):
        """Store a pending AuthnRequest and return a token."""
        token = os.urandom(32).hex()
        self.pending_requests[token] = {
            "data": authn_request_data,
            "created": utc_now(),
        }
        return token

    def get_pending_request(self, token):
        """Retrieve and remove a pending AuthnRequest."""
        if not token or token not in self.pending_requests:
            return None

        pending = self.pending_requests[token]
        # Pending requests expire after 5 minutes
        if (utc_now() - pending["created"]).total_seconds() > 300:
            del self.pending_requests[token]
            return None

        del self.pending_requests[token]
        return pending["data"]

    def generate_csrf_token(self, session_id):
        """Generate a CSRF token tied to a session."""
        token = os.urandom(32).hex()
        if session_id in self.sessions:
            self.sessions[session_id]["csrf_token"] = token
        return token

    def validate_csrf_token(self, session_id, token):
        """Validate a CSRF token."""
        if not session_id or session_id not in self.sessions:
            return False
        session = self.sessions[session_id]
        stored_token = session.get("csrf_token")
        if not stored_token or not token:
            return False
        return hashlib.compare_digest(stored_token, token)


